// Size via inline style, not the height attribute: Tailwind preflight (in the app and
// on host sites) sets `img { height: auto }`, which overrides presentation attributes
const artImg = (webpB64: string): string =>
    `<img src="data:image/webp;base64,${webpB64}" alt="" style="height: 48px; width: auto; display: block">`

